        {"id": "r26", "q": "Сколько звуков в слове 'Якорь'?", "o": ["4", "5", "6", "7"], "a": 1, "e": "Якорь: [й'], [а], [к], [а], [р'] - 5 звуков.", "t": "Фонетика", "d": 2},
