        {"id": "p25", "q": "Температура газа 27°C. Найдите её в Кельвинах.", "o": ["250 К", "273 К", "300 К", "327 К"], "a": 2, "e": "T = 27 + 273 = 300 K.", "t": "Молекулярная физика", "d": 1},
