        {"id": "s7", "q": "К какому виду налогов относится НДС?", "o": ["Прямой налог", "Косвенный налог", "Местный налог", "Прогрессивный налог"], "a": 1, "e": "НДС - косвенный налог, т.к. включается в цену товара и фактически уплачивается потребителем.", "t": "Экономика", "d": 2},
        {"id": "s8", "q": "Что относится к полномочиям Президента РФ?", "o": ["Утверждение бюджета", "Назначение Председателя Правительства", "Принятие законов", "Назначение выборов Президента"], "a": 1, "e": "Президент назначает Председателя Правительства с согласия Госдумы. Бюджет утверждает Дума, законы принимает ФС.", "t": "Политика", "d": 3},
    
