        {"id": "s16", "q": "Что относится к доходам государственного бюджета?", "o": ["Субсидии", "Налоги", "Дотации", "Трансферты"], "a": 1, "e": "Налоги - основной источник доходов бюджета. Остальное - расходы.", "t": "Экономика", "d": 1},
