        {"id": "c8", "q": "Какая связь в молекуле H2O?", "o": ["Ионная", "Ковалентная полярная", "Ковалентная неполярная", "Металлическая"], "a": 1, "e": "Вода - ковалентная полярная связь (разные элементы - H и O).", "t": "Химическая связь", "d": 1},
        {"id": "c9", "q": "Сколько атомов в 1 моле H2O?", "o": ["6*10^23", "1.8*10^24", "3*10^23", "12*10^23"], "a": 1, "e": "1 моль H2O = 6*10^23 молекул. В каждой 3 атома. Итого 1.8*10^24.", "t": "Количество вещества", "d": 2},
        {"id": "c10", "q": "Какой газ выделяется при взаимодействии цинка с HCl?", "o": ["Кислород", "Водород", "Хлор", "Хлороводород"], "a": 1, "e": "Zn + 2HCl = ZnCl2 + H2↑", "t": "Неорганическая химия", "d": 1},
