        {"id": "e8", "q": "Fill in: 'He is not tall ___ to reach the shelf.'", "o": ["enough", "too", "so", "very"], "a": 0, "e": "Конструкция: adjective + enough + infinitive.", "t": "Grammar: Adverbs", "d": 2},
        {"id": "e9", "q": "Choose the correct form: 'If I ___ you, I would accept.'", "o": ["am", "was", "were", "be"], "a": 2, "e": "Second Conditional: If I were you...", "t": "Grammar: Conditionals", "d": 2},
        {"id": "e10", "q": "What is the opposite of 'ancient'?", "o": ["old", "modern", "historic", "classic"], "a": 1, "e": "Ancient = древний, modern = современный (антоним).", "t": "Vocabulary", "d": 1},
